This class stores an initializer_list as a member, which causes dangling-reference problems. Which option correctly identifies the bug?

```cpp
#include <iostream>
#include <initializer_list>
class Nums {
    std::initializer_list<int> stored;
public:
    Nums(std::initializer_list<int> list) : stored{list} {}
    int front() const { return *stored.begin(); }
};
int main() {
    Nums n{1, 2, 3};
    std::cout << n.front() << "\n";
}
```

What does this program print?

```cpp
#include <iostream>
#include <initializer_list>
int sumAll(std::initializer_list<int> vals) {
    int total = 0;
    for (int v : vals) total += v;
    return total;
}
int main() {
    std::cout << sumAll({1, 2, 3, 4}) << "\n";
    std::cout << sumAll({10, 20}) << "\n";
}
```
